// ---------------------------------------------------------------------------
// Phase 1: Anchor Fingerprint
// ---------------------------------------------------------------------------

/// Complete DNA fingerprint of the anchor word.
/// Tier: T3 (σ + μ + ν + N + κ)
#[derive(Debug, Serialize)]
pub struct AnchorFingerprint {
    pub word: String,
    pub strand_len: usize,
    pub entropy: f64,
    pub gc_content: f64,
    pub base_dist: [usize; 4],
    pub mean_tension: f64,
    pub peak_tension: f64,
    pub tension_variance: f64,
    pub dominant_period: usize,
    pub mode_count: usize,
    pub spectral_entropy: f64,
    pub energy_level: u32,
    pub total_energy: f64,
    pub energy_density: f64,
}

/// Phase 1: Encode anchor and compute full fingerprint.
pub fn phase1_fingerprint(anchor: &str) -> AnchorFingerprint {
    let ore = lexicon::mine(anchor);
    let tension = string_theory::word_tension(anchor);
    let spectrum = string_theory::word_spectrum(anchor);
    let energy = string_theory::string_energy(anchor);

    AnchorFingerprint {
        word: anchor.to_string(),
        strand_len: ore.length,
        entropy: ore.entropy,
        gc_content: ore.gc_content,
        base_dist: lexicon::nuc_distribution(&ore.strand),
        mean_tension: tension.mean_tension,
        peak_tension: tension.peak_tension,
        tension_variance: tension.variance,
        dominant_period: spectrum.dominant_period,
        mode_count: spectrum.modes.len(),
        spectral_entropy: spectrum.spectral_entropy,
        energy_level: energy.energy_level,
        total_energy: energy.total_energy,
        energy_density: energy.energy_density,
    }
}

// ---------------------------------------------------------------------------
// Phase 2: Resonance Screening
// ---------------------------------------------------------------------------

/// Resonance measurement for one candidate word.
/// Tier: T2-C (κ + ν + N + μ)
#[derive(Debug, Clone, Serialize)]
pub struct ResonanceResult {
    pub word: String,
    pub overlap: f64,
    pub harmony: f64,
    pub dissonance: f64,
    pub tension_alignment: f64,
    pub tier: u8,
    pub tier_name: String,
}

/// Phase 2: Compute resonance for all candidates and classify into tiers.
pub fn phase2_resonance(anchor: &str, candidates: &[String]) -> Vec<ResonanceResult> {
    let mut results: Vec<ResonanceResult> = candidates
        .iter()
        .map(|c| {
            let r = string_theory::word_resonance(anchor, c);
            let (tier, tier_name) = classify_harmony(r.harmony);
            ResonanceResult {
                word: c.clone(),
                overlap: r.overlap,
                harmony: r.harmony,
                dissonance: r.dissonance,
                tension_alignment: r.tension_alignment,
                tier,
                tier_name,
            }
        })
        .collect();

    // Sort: tier asc (best first), then overlap desc within tier
    results.sort_by(|a, b| {
        a.tier
            .cmp(&b.tier)
            .then_with(|| b.overlap.partial_cmp(&a.overlap).unwrap_or(std::cmp::Ordering::Equal))
    });

    results
}

/// Classify harmony score into tier.
fn classify_harmony(harmony: f64) -> (u8, String) {
    if (harmony - 1.0).abs() < f64::EPSILON {
        (1, "Pure Harmonic".to_string())
    } else if harmony > 0.5 {
        (2, "Favorable Tension".to_string())
    } else if (harmony - 0.5).abs() < f64::EPSILON {
        (3, "Creative Tension".to_string())
    } else {
        (4, "Dominant Dissonance".to_string())
    }
}

// ---------------------------------------------------------------------------
// Phase 2b: Tier Classification
